                               rdfs:comment        "A process can have at least one output variable (substance)"@en ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      pplan:hasOutputVar ;
                               owl:someValuesFrom  pplan:Variable
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
